import { useState, useEffect } from "react";
import { useSearchParams } from "react-router-dom";
import { motion, AnimatePresence, useReducedMotion } from "framer-motion";
import { TrendingUp, TrendingDown, Sparkles, X } from "lucide-react";
import { useMarket } from "@/lib/MarketContext";
import { lastSeenAt, markSnapshotSeen } from "@/lib/useNotesAlerts";
import { fmt } from "@/lib/parseItem";
import { openItem } from "./DetailDrawer";

export default function WhatsChanged() {
  const { snapshotDiff } = useMarket();
  const [dismissed, setDismissed] = useState(false);
  const [searchParams, setSearchParams] = useSearchParams();
  const prefersReduced = useReducedMotion();

  useEffect(() => { setDismissed(false); }, [snapshotDiff?.at]);

  if (!snapshotDiff || !snapshotDiff.items?.length) return null;
  // Only show if there's been at least a few hours since last seen (or never)
  const seen = lastSeenAt();
  const ageH = (Date.now() - (snapshotDiff.at || 0)) / 3600000;
  if (ageH < 0.25) return null; // skip if snapshot is too recent (< 15 min)
  if (seen >= snapshotDiff.at) return null;
  if (dismissed) return null;

  const dismiss = () => { markSnapshotSeen(); setDismissed(true); };

  if (prefersReduced) {
    return (
      <section
        data-testid="whats-changed"
        className="relative py-8"
      >
        <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
          <div className="relative bg-emerald-500/[0.06] border border-emerald-500/20 rounded-2xl p-5 sm:p-6 overflow-hidden">
            <div className="flex items-start justify-between gap-4 mb-4">
              <div>
                <div className="inline-flex items-center gap-2 font-mono text-[10px] uppercase tracking-[0.25em] text-emerald-300">
                  <Sparkles className="w-3 h-3" /> What changed since you last looked
                </div>
                <h2 className="mt-2 font-heading text-2xl sm:text-3xl tracking-tight font-bold">
                  Top movers &middot; since {timeAgo(snapshotDiff.at)}
                </h2>
              </div>
              <button onClick={dismiss} aria-label="Dismiss" className="p-1.5 text-zinc-500 hover:text-white transition-colors">
                <X className="w-4 h-4" />
              </button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
              {snapshotDiff.items.map((it) => (
                <button
                  key={it.key}
                  onClick={() => openItem(searchParams, setSearchParams, it.key)}
                  data-testid={`wc-item-${it.key}`}
                  className="group text-left bg-bg-base/60 hover:bg-bg-base border border-white/10 hover:border-emerald-500/40 rounded-xl p-4 transition-all"
                >
                  <div className="font-medium text-white text-sm truncate group-hover:text-emerald-400 transition-colors">{it.name}</div>
                  <div className="mt-2 flex items-baseline gap-2">
                    <span className="font-mono text-base tabular text-white">{fmt(it.newMedian)}</span>
                    <span className={`inline-flex items-center gap-0.5 font-mono text-xs tabular ${it.pct > 0 ? "text-emerald-400" : "text-red-400"}`}>
                      {it.pct > 0 ? <TrendingUp className="w-3 h-3" /> : <TrendingDown className="w-3 h-3" />}
                      {it.pct > 0 ? "+" : ""}{it.pct.toFixed(1)}%
                    </span>
                  </div>
                  <div className="mt-1 font-mono text-[10px] text-zinc-500 tabular">
                    was {fmt(it.oldMedian)}
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>
      </section>
    );
  }

  return (
    <AnimatePresence>
      <motion.section
        data-testid="whats-changed"
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: -10 }}
        transition={{ duration: 0.5, ease: [0.16, 1, 0.3, 1] }}
        className="relative py-8"
      >
        <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
          <div className="relative bg-emerald-500/[0.06] border border-emerald-500/20 rounded-2xl p-5 sm:p-6 overflow-hidden">
            <div className="flex items-start justify-between gap-4 mb-4">
              <div>
                <div className="inline-flex items-center gap-2 font-mono text-[10px] uppercase tracking-[0.25em] text-emerald-300">
                  <Sparkles className="w-3 h-3" /> What changed since you last looked
                </div>
                <h2 className="mt-2 font-heading text-2xl sm:text-3xl tracking-tight font-bold">
                  Top movers · since {timeAgo(snapshotDiff.at)}
                </h2>
              </div>
              <button onClick={dismiss} aria-label="Dismiss" className="p-1.5 text-zinc-500 hover:text-white transition-colors">
                <X className="w-4 h-4" />
              </button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
              {snapshotDiff.items.map((it) => (
                <button
                  key={it.key}
                  onClick={() => openItem(searchParams, setSearchParams, it.key)}
                  data-testid={`wc-item-${it.key}`}
                  className="group text-left bg-bg-base/60 hover:bg-bg-base border border-white/10 hover:border-emerald-500/40 rounded-xl p-4 transition-all"
                >
                  <div className="font-medium text-white text-sm truncate group-hover:text-emerald-400 transition-colors">{it.name}</div>
                  <div className="mt-2 flex items-baseline gap-2">
                    <span className="font-mono text-base tabular text-white">{fmt(it.newMedian)}</span>
                    <span className={`inline-flex items-center gap-0.5 font-mono text-xs tabular ${it.pct > 0 ? "text-emerald-400" : "text-red-400"}`}>
                      {it.pct > 0 ? <TrendingUp className="w-3 h-3" /> : <TrendingDown className="w-3 h-3" />}
                      {it.pct > 0 ? "+" : ""}{it.pct.toFixed(1)}%
                    </span>
                  </div>
                  <div className="mt-1 font-mono text-[10px] text-zinc-500 tabular">
                    was {fmt(it.oldMedian)}
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>
      </motion.section>
    </AnimatePresence>
  );
}

function timeAgo(ms) {
  if (!ms) return "—";
  const diff = (Date.now() - ms) / 1000;
  if (diff < 3600) return Math.max(1, Math.floor(diff / 60)) + "m ago";
  if (diff < 86400) return Math.floor(diff / 3600) + "h ago";
  if (diff < 7 * 86400) return Math.floor(diff / 86400) + "d ago";
  return new Date(ms).toLocaleDateString();
}
