import { useState } from "react";
import { Plus, Minus } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { faqs } from "@/lib/mockData";
import { Reveal } from "./motion";

export default function FAQ() {
  const [open, setOpen] = useState(0);
  return (
    <section
      id="faq"
      data-testid="faq-section"
      className="relative py-24 md:py-32"
    >
      <div className="max-w-5xl mx-auto px-6 md:px-12">
        <Reveal className="mb-16">
          <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-emerald-400 mb-4">
            / Frequently asked
          </div>
          <h2 className="font-heading text-4xl sm:text-5xl lg:text-6xl tracking-tighter font-black leading-[0.95]">
            Questions, answered.
          </h2>
        </Reveal>

        <div className="border-t border-white/10">
          {faqs.map((f, i) => {
            const isOpen = open === i;
            return (
              <motion.div
                key={f.q}
                data-testid={`faq-item-${i}`}
                initial={{ opacity: 0, y: 20 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true, margin: "-50px" }}
                transition={{ delay: i * 0.05, duration: 0.5 }}
                className="border-b border-white/10"
              >
                <button
                  data-testid={`faq-toggle-${i}`}
                  aria-expanded={isOpen}
                  onClick={() => setOpen(isOpen ? -1 : i)}
                  className="w-full flex items-center justify-between gap-6 py-7 text-left group"
                >
                  <span className={`font-heading text-lg sm:text-2xl tracking-tight font-bold transition-colors ${isOpen ? "text-emerald-400" : "text-white group-hover:text-emerald-300"}`}>
                    {f.q}
                  </span>
                  <div className={`shrink-0 w-10 h-10 grid place-items-center rounded-full border transition-all ${isOpen ? "border-emerald-500 bg-emerald-500/10" : "border-white/15 group-hover:border-white/40"}`}>
                    {isOpen ? <Minus className="w-4 h-4 text-emerald-400" /> : <Plus className="w-4 h-4" />}
                  </div>
                </button>
                <AnimatePresence initial={false}>
                  {isOpen && (
                    <motion.div
                      key="content"
                      initial={{ height: 0, opacity: 0 }}
                      animate={{ height: "auto", opacity: 1 }}
                      exit={{ height: 0, opacity: 0 }}
                      transition={{ duration: 0.4, ease: [0.16, 1, 0.3, 1] }}
                      className="overflow-hidden"
                      aria-hidden={!isOpen}
                    >
                      <p className="text-zinc-400 leading-relaxed max-w-3xl pb-7">{f.a}</p>
                    </motion.div>
                  )}
                </AnimatePresence>
              </motion.div>
            );
          })}
        </div>
      </div>
    </section>
  );
}
